module top_module(
    input  wire        CLK,
    input  wire        RST,
    input  wire        EN,
    output wire [3:0]  Q
);reg [3:0] invalid_count;

    always @(posedge CLK) begin
        if (RST) begin
            invalid_count <= 4'b0;
        end
        else if (EN) begin
            invalid_count <= invalid_count + 1;
        end
    end

    assign Q = invalid_count;

endmodule
